final class PushNotificationManager {
    func requestAuthorization(completion: @escaping (Bool, Error?) -> Void) {
        UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .badge, .sound], completionHandler: completion)
    }

    func getAuthorizationStatus(completion: @escaping (String) -> Void) {
        UNUserNotificationCenter.current().getNotificationSettings { settings in
            let status: String
            switch settings.authorizationStatus {
            case .notDetermined:
                status = "notDetermined"
            case .denied:
                status = "denied"
            case .authorized:
                status = "authorized"
            case .provisional:
                status = "provisional"
            case .ephemeral:
                status = "ephemeral"
            @unknown default:
                status = "unknown"
            }
            DispatchQueue.main.async {
                completion(status)
            }
        }
    }
}

final class InAppPurchaseManager: NSObject {
    enum IAPError: Error {
        case productNotFound
        case paymentsDisabled
        case unknown
    }

    private var productsRequest: SKProductsRequest?
    private var productsCompletion: ((Result<[SKProduct], Error>) -> Void)?
    private var purchaseCompletion: ((Result<String, Error>) -> Void)?
    private var restoreCompletion: ((Result<[String], Error>) -> Void)?
    private var availableProducts: [SKProduct] = []
    private var restoredProductIDs: [String] = []

    override init() {
        super.init()
        SKPaymentQueue.default().add(self)
    }

    deinit {
        SKPaymentQueue.default().remove(self)
    }

    func fetchProducts(identifiers: [String], completion: @escaping (Result<[SKProduct], Error>) -> Void) {
        productsRequest?.cancel()
        productsCompletion = completion

        let request = SKProductsRequest(productIdentifiers: Set(identifiers))
        request.delegate = self
        productsRequest = request
        request.start()
    }

    func purchase(productId: String, completion: @escaping (Result<String, Error>) -> Void) {
        guard SKPaymentQueue.canMakePayments() else {
            completion(.failure(IAPError.paymentsDisabled))
            return
        }

        guard let product = availableProducts.first(where: { $0.productIdentifier == productId }) else {
            completion(.failure(IAPError.productNotFound))
            return
        }

        purchaseCompletion = completion
        let payment = SKPayment(product: product)
        SKPaymentQueue.default().add(payment)
    }

    func restorePurchases(completion: @escaping (Result<[String], Error>) -> Void) {
        restoredProductIDs.removeAll()
        restoreCompletion = completion
        SKPaymentQueue.default().restoreCompletedTransactions()
    }
}

extension InAppPurchaseManager: SKProductsRequestDelegate {
    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        availableProducts = response.products
        productsCompletion?(.success(response.products))
        productsCompletion = nil
    }

    func request(_ request: SKRequest, didFailWithError error: Error) {
        productsCompletion?(.failure(error))
        productsCompletion = nil
    }
}

extension InAppPurchaseManager: SKPaymentTransactionObserver {
    func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) {
        for transaction in transactions {
            switch transaction.transactionState {
            case .purchased:
                let id = transaction.transactionIdentifier ?? UUID().uuidString
                purchaseCompletion?(.success(id))
                purchaseCompletion = nil
                queue.finishTransaction(transaction)

            case .failed:
                let error = transaction.error ?? IAPError.unknown
                purchaseCompletion?(.failure(error))
                purchaseCompletion = nil
                queue.finishTransaction(transaction)

            case .restored:
                restoredProductIDs.append(transaction.payment.productIdentifier)
                queue.finishTransaction(transaction)

            case .purchasing, .deferred:
                break

            @unknown default:
                break
            }
        }
    }

    func paymentQueueRestoreCompletedTransactionsFinished(_ queue: SKPaymentQueue) {
        restoreCompletion?(.success(restoredProductIDs))
        restoreCompletion = nil
    }

    func paymentQueue(_ queue: SKPaymentQueue, restoreCompletedTransactionsFailedWithError error: Error) {
        restoreCompletion?(.failure(error))
        restoreCompletion = nil
    }
}

